import{_ as a,c as s,o as i,aA as o}from"./chunks/framework.CLrzXryn.js";const n="/RadialBasisFunctions.jl/previews/PR125/assets/3d_laplacian3d_h_ref.CVEOTQuQ.png",t="/RadialBasisFunctions.jl/previews/PR125/assets/3d_gradient3d_h_ref.pL-QTDwE.png",c="/RadialBasisFunctions.jl/previews/PR125/assets/3d_laplacian_k_ref.CAyg4Yor.png",g=JSON.parse('{"title":"3D Extensions","description":"","frontmatter":{},"headers":[],"relativePath":"guides/convergence/3d.md","filePath":"guides/convergence/3d.md","lastUpdated":null}'),r={name:"guides/convergence/3d.md"};function l(d,e,p,h,m,D){return i(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="3D-Extensions" tabindex="-1">3D Extensions <a class="header-anchor" href="#3D-Extensions" aria-label="Permalink to &quot;3D Extensions {#3D-Extensions}&quot;">​</a></h1><p>RBF-FD generalizes directly to 3D: stencil neighborhoods become spheres instead of disks, and <code>poly_deg</code> is interpreted in 3D polynomial space. This page verifies that the 2D convergence story carries over and flags the main practical difference: stencil sizes must grow to accommodate the larger 3D polynomial basis.</p><p>Test function: <code>g(x) = 1 + sin(3x₁) + cos(2x₂) + sin(x₃)</code> (separable trig, known Laplacian and gradient). Point sweep: <code>n_side ∈ {8, 12, 16, 20}</code> → <code>N ∈ {512, 1728, 4096, 8000}</code>.</p><h2 id="Laplacian-3D" tabindex="-1">Laplacian (3D) <a class="header-anchor" href="#Laplacian-3D" aria-label="Permalink to &quot;Laplacian (3D) {#Laplacian-3D}&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Excluded: PHS1/p=1</p><p>Omitted from the plot — same pathology as in 2D. Never use PHS1 for second-derivative operators.</p></div><p><img src="'+n+'" alt=""></p><p>Same convergence-order story as 2D: PHS3/p=2 gives approximately <code>O(h²)</code>, PHS5/p=3 gives <code>O(h⁴)</code>, PHS7/p=4 gives <code>O(h⁶)</code>. The slopes look shallower in this plot than in 2D because the x-axis range is only ~1.2 decades (vs ~1.7 in 2D) — a consequence of <code>N = n_side³</code> making 3D sweeps expensive.</p><h2 id="Gradient-3D" tabindex="-1">Gradient (3D) <a class="header-anchor" href="#Gradient-3D" aria-label="Permalink to &quot;Gradient (3D) {#Gradient-3D}&quot;">​</a></h2><p><img src="'+t+'" alt=""></p><p>First-derivative convergence also carries over cleanly to 3D.</p><h2 id="Stencil-size-3D-Laplacian" tabindex="-1">Stencil size (3D Laplacian) <a class="header-anchor" href="#Stencil-size-3D-Laplacian" aria-label="Permalink to &quot;Stencil size (3D Laplacian) {#Stencil-size-3D-Laplacian}&quot;">​</a></h2><p><img src="'+c+'" alt=""></p><p>The key practical difference from 2D: <strong>3D stencils need to be larger</strong> because the 3D polynomial basis has more monomials at each degree (<code>binomial(3+p, p)</code> vs <code>binomial(2+p, p)</code> in 2D). For example, <code>poly_deg=3</code> in 3D has 20 monomials vs 10 in 2D, so a 3D stencil with <code>k ≈ 35–50</code> plays the same role as a 2D stencil with <code>k ≈ 15–20</code>. <code>autoselect_k(data, basis)</code> accounts for this automatically.</p>',13)])])}const u=a(r,[["render",l]]);export{g as __pageData,u as default};
